//$Id$
import { d3_map } from '../../core/d3-constants';

let fill_E = ['fill', 'fillColor', 'fillOpacity'],
    stroke_E = ['stroke', 'strokeColor', 'strokeOpacity', 'strokeWidth', 'strokeDash'],
    //
    group_E = ['x', 'y'],
    rect_E = ['x', 'y', 'x0', 'y0', 'url', ...fill_E, ...stroke_E],
    point_E = ['x', 'y', 'size', 'shape', 'url', ...fill_E, ...stroke_E],
    arc_E = ['angle', 'radius', 'angle0', 'radius0', 'url', ...fill_E, ...stroke_E],
    image_E = ['x', 'y', 'width', 'height', 'url', ...fill_E, ...stroke_E],
    polygon_E = ['points', 'url', ...fill_E, ...stroke_E],
    text_E = ['text', 'size', ...fill_E, ...stroke_E];

export let ALLOWED_ENCODES = d3_map();
ALLOWED_ENCODES.set('group', group_E);
ALLOWED_ENCODES.set('rect', rect_E);
ALLOWED_ENCODES.set('point', point_E);
ALLOWED_ENCODES.set('arc', arc_E);
ALLOWED_ENCODES.set('image', image_E);
ALLOWED_ENCODES.set('polygon', polygon_E);
ALLOWED_ENCODES.set('text', text_E);
